var createBooking = async (data) => {
  const service = await prisma.service.findUnique({
    where: { id: data.serviceId }
  });
  if (!service) {
    throw new AppError(httpStatus13.NOT_FOUND, "Service not found");
  }
  const booking = await prisma.booking.create({
    data: {
      customerId: data.customerId,
      serviceId: data.serviceId,
      technicianId: service.technicianId,
      scheduleDate: data.scheduleDate ? new Date(data.scheduleDate) : null
    },
    include: {
      service: true,
      customer: { omit: { password: true } },
      technician: { omit: { password: true } }
    }
  });
  return booking;
};
var getMyBookings3 = async (userId, role) => {
  const where = role === "CUSTOMER" ? { customerId: userId } : role === "TECHNICIAN" ? { technicianId: userId } : {};
  return prisma.booking.findMany({
    where,
    include: {
      service: true,
      customer: { omit: { password: true } },
      technician: { omit: { password: true } },
      payment: true,
      review: true
    },
    orderBy: { id: "desc" }
  });
};
var getBookingById = async (bookingId, userId, role) => {
  const booking = await prisma.booking.findUnique({
    where: { id: bookingId },
    include: {
      service: true,
      customer: { omit: { password: true } },
      technician: { omit: { password: true } },
      payment: true,
      review: true
    }
  });
  if (!booking) {
    throw new AppError(httpStatus13.NOT_FOUND, "Booking not found");
  }
  if (role === "CUSTOMER" && booking.customerId !== userId) {
    throw new AppError(
      httpStatus13.FORBIDDEN,
      "You can only view your own bookings"
    );
  }
  if (role === "TECHNICIAN" && booking.technicianId !== userId) {
    throw new AppError(
      httpStatus13.FORBIDDEN,
      "You can only view your own bookings"
    );
  }
  return booking;
};
var cancelBooking = async (bookingId, customerId) => {
  const booking = await prisma.booking.findUnique({
    where: { id: bookingId }
  });
  if (!booking) {
    throw new AppError(httpStatus13.NOT_FOUND, "Booking not found");
  }
  if (booking.customerId !== customerId) {
    throw new AppError(
      httpStatus13.FORBIDDEN,
      "You can only cancel your own bookings"
    );
  }
  const cancellableStatuses = ["REQUESTED", "ACCEPTED", "PAID"];
  if (!cancellableStatuses.includes(booking.status)) {
    throw new AppError(
      httpStatus13.BAD_REQUEST,
      "Cannot cancel booking at current status"
    );
  }
  return prisma.booking.update({
    where: { id: bookingId },
    data: { status: "CANCELLED" },
    include: {
      service: true,
      customer: { omit: { password: true } },
      technician: { omit: { password: true } }
    }
  });
};
var bookingService = {
  createBooking,
  getMyBookings: getMyBookings3,
  getBookingById,
  cancelBooking
};

